                        <AuditRecordsReport></AuditRecordsReport>
                    </div>
                    <div id="BilledUnbilledReport" class="tab-pane" :class="{ 'active show': activeKey == 2 }" v-if="activeKey == 2">
                        <BilledUnbilledReport></BilledUnbilledReport>
                    </div>
                    <div id="BilledUnbilledSummaryReport" class="tab-pane" :class="{ 'active show': activeKey == 3 }" v-if="activeKey == 3">
                        <BilledUnbilledSummaryReport></BilledUnbilledSummaryReport>
                    </div>
                     <div id="BillingRuleReport" class="tab-pane" :class="{ 'active show': activeKey == 4 }" v-if="activeKey == 4">
                        <BillingRuleReport></BillingRuleReport>
