                        <FlagDetailReport></FlagDetailReport>
                    </div>
                   <div id="FlagSummaryReport" class="tab-pane" :class="{ 'active show': activeKey == 10 }" v-if="activeKey == 10">
                        <FlagSummaryReport></FlagSummaryReport>
                    </div>
                     <div id="InvoiceDetailReport" class="tab-pane" :class="{ 'active show': activeKey == 11 }" v-if="activeKey == 11">
                        <InvoiceDetailReport></InvoiceDetailReport>
                    </div>
                    <div id="InvoiceSummaryByWork" class="tab-pane" :class="{ 'active show': activeKey == 12 }" v-if="activeKey == 12">
                        <InvoiceSummaryByWork></InvoiceSummaryByWork>
                    </div>
                    <div id="InvoiceSummary" class="tab-pane" :class="{ 'active show': activeKey == 13 }" v-if="activeKey == 13">
                        <InvoiceSummary></InvoiceSummary>
                    </div>
                   <div id="Milestone" class="tab-pane" :class="{ 'active show': activeKey == 14 }" v-if="activeKey == 14">
                        <Milestone></Milestone>
                    </div>
                   <div id="MissingRatesInWorkcode" class="tab-pane" :class="{ 'active show': activeKey == 15 }" v-if="activeKey == 15">
                        <MissingRatesInWorkcode></MissingRatesInWorkcode>
                    </div>
                    <div id="MissingRatesInActivities" class="tab-pane" :class="{ 'active show': activeKey == 16 }" v-if="activeKey == 16">
                        <MissingRatesInActivities></MissingRatesInActivities>
                    </div>
                    <div id="MissingSetupReport" class="tab-pane" :class="{ 'active show': activeKey == 17 }" v-if="activeKey == 17">
                        <MissingSetupReport></MissingSetupReport>
                    </div>
                    <div id="MonthlyRevenueDetailReport" class="tab-pane" :class="{ 'active show': activeKey == 18 }" v-if="activeKey == 18">
                        <MonthlyRevenueDetailReport></MonthlyRevenueDetailReport>
                    </div>
                    <div id="MonthlyRevenueSummaryReport" class="tab-pane" :class="{ 'active show': activeKey == 19 }" v-if="activeKey == 19">
                        <MonthlyRevenueSummaryReport></MonthlyRevenueSummaryReport>
                    </div>
                     <div id="MTDReport" class="tab-pane" :class="{ 'active show': activeKey == 20 }" v-if="activeKey == 20">
                        <MTDReport></MTDReport>
                    </div> 
                    <div id="NotesReport" class="tab-pane" :class="{ 'active show': activeKey == 21 }" v-if="activeKey == 21">
                        <NotesReport></NotesReport>
                    </div> 
                    <div id="ProcessedUnProccesedReport" class="tab-pane" :class="{ 'active show': activeKey == 22 }" v-if="activeKey == 22">
                        <ProcessedUnProccesedReport></ProcessedUnProccesedReport>
                    </div> 
                    <div id="RevenueByCustomerReport" class="tab-pane" :class="{ 'active show': activeKey == 23 }" v-if="activeKey == 23">
                        <RevenueByCustomerReport></RevenueByCustomerReport>
                    </div> 
                    <div id="SuppressedCodeReport" class="tab-pane" :class="{ 'active show': activeKey == 24 }" v-if="activeKey == 24">
                        <SuppressedCodeReport></SuppressedCodeReport>
                    </div>
                    <div id="TicketAuditLogReport" class="tab-pane" :class="{ 'active show': activeKey == 25 }" v-if="activeKey == 25">
                        <TicketAuditLogReport></TicketAuditLogReport>
                    </div>
                </div>
            </div>
        </div>
        <!-- right-content End here -->
    </div>
    </template>
    
    <script>
    
    import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
    import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
    import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
    import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
    import MTDReport from "../InvoiceReport/MTDReport.vue"
    import AccountDetailReport from "../InvoiceReport/AccountDetailReport.vue";
    import AuditRecordsReport from "../InvoiceReport/AuditRecordsReport.vue"; 
    import BilledUnbilledReport from "../InvoiceReport/BilledUnbilledReport.vue"; 
    import BilledUnbilledSummaryReport from "../InvoiceReport/BilledUnbilledSummaryReport.vue";
    import BillingRuleReport from "../InvoiceReport/BillingRuleReport.vue";
    import BillingRueMissingReports from "../InvoiceReport/BillingRueMissingReports.vue";
    import BillingServiceListReport from "../InvoiceReport/BillingServiceListReport.vue";
    import BillingServiceReport from "../InvoiceReport/BillingServiceReport.vue";
    import ContractDetailReport from "../InvoiceReport/ContractDetailReport.vue";
    import FlagDetailReport from "../InvoiceReport/FlagDetailReport.vue";
    import FlagSummaryReport from "../InvoiceReport/FlagSummaryReport.vue";
    import InvoiceDetailReport from "../InvoiceReport/InvoiceDetailReport.vue";
    import InvoiceSummaryByWork from "../InvoiceReport/InvoiceSummaryByWork.vue";
    import InvoiceSummary from "../InvoiceReport/InvoiceSummaryReport.vue";
    import Milestone from "../InvoiceReport/MileStoneReport.vue";
    import MissingRatesInWorkcode from "../InvoiceReport/MissingRatesInWorkcode.vue";
    import MissingRatesInActivities from "../InvoiceReport/MissingRatesInActivity.vue";
    import MissingSetupReport from "../InvoiceReport/MissingSetupReport.vue";
    import MonthlyRevenueDetailReport from "../InvoiceReport/MonthlyRevenueDetailReport.vue";
    import MonthlyRevenueSummaryReport from "../InvoiceReport/MonthlyRevenueSummaryReport.vue";
    import NotesReport from "../InvoiceReport/NotesReport.vue";
    import ProcessedUnProccesedReport from "../InvoiceReport/ProcessedUnprocessedReport.vue";
    import RevenueByCustomerReport from "../InvoiceReport/RevenueByCustomerReport.vue";
    import SuppressedCodeReport from '../InvoiceReport/SuppressedCodeReport.vue';  
    import TicketAuditLogReport from '../InvoiceReport/TicketAuditLogReport.vue';  
    import DataServices from "../../services/DataService";

    export default {
        components: {
            AccountDetailReport,
            AuditRecordsReport,
            BilledUnbilledReport,
            BilledUnbilledSummaryReport,
            BillingRuleReport,
            BillingRueMissingReports,
            BillingServiceListReport,
            BillingServiceReport,
            ContractDetailReport,
            FlagDetailReport,
            FlagSummaryReport,
            InvoiceDetailReport,
            InvoiceSummaryByWork,
            InvoiceSummary,
            Milestone,
            MissingRatesInWorkcode,
            MissingRatesInActivities,
            MissingSetupReport,
            MonthlyRevenueDetailReport,
            MonthlyRevenueSummaryReport,
            MTDReport,
            NotesReport,
            ProcessedUnProccesedReport,
            RevenueByCustomerReport,
            SuppressedCodeReport,
            TicketAuditLogReport
            // ProductReport,
        },
        data() {
            return {
                activeKey: 0,
                tabNames: [],
                IsUsicval : "",
                IsCheck: "",
                searchQuery: "",
                Isrevenue:"",
                NotesVal:"",
                UserLicenseModules: []
            };
        },
        mounted() {
            this.activateTab(0);
            
        },
        computed: {
        filteredTabs() {
            if (!this.searchQuery) {           
                return this.tabNames.map((name, index) => ({
                    name,
                    index,
                    icon: this.getTabIcon(name)
                }));
            }
            const query = this.searchQuery.toLowerCase();
            const filtered = this.tabNames
                .map((name, index) => ({
                    name,
                    index,
                    icon: this.getTabIcon(name)
                }))
                .filter(tab => this.$t(tab.name).toLowerCase().includes(query));
    
            if (query.trim() !== '' && filtered.length === 0) {           
                return [{ name: 'No tabs found for "' + this.searchQuery + '"', index: -1, icon: 'no-icon' }];
            }
    
            return filtered;
        },
        activeTabName() {
            return this.tabNames[this.activeKey]; // Returns the name of the currently active tab
        }
        
    },
    created: async function () {
        var vm = this;
        await vm.GetNotes();
        await vm.IsUsic();
        await vm.GetUserLicenseModulesReport();
        await vm.setTabNames();
       
    },
    methods: {
            setTabNames: async function()  {
                debugger;
                var vm = this;
            if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'INVOICEDETAILREPORT')){
                vm.tabNames.push( "Invoice Detail report")
            }
            if(vm.IsCheck){
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'MTDREPORT')){
                vm.tabNames.push( "MTD Report")
            }
            }
            if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'MILESTONEREPORT')){
                vm.tabNames.push( "Milestone Report")
            }
            if(vm.IsUsicval){
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'HISTORICALDETAILEDDATAREPORT')){
                vm.tabNames.push( "Billed/Unbilled Report")
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'HISTORICALDETAILEDDATASUMMARYREPORT')){
                    vm.tabNames.push( "Billed/Unbilled Summary Report" )
                }
                if( vm.GetUserInfo.UserType ==  "CA" || vm.GetUserInfo.UserType == "PM"){
                    if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'FLAGSUMMARYREPORT')){
                    vm.tabNames.push( "Flag Summary Report" )
                    }
                     if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'FLAGDETAILREPORT')){
                    vm.tabNames.push( "Flag Detail Report" )
                    }
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'MONTHLYREVENUEDETAILREPORT')){
                    vm.tabNames.push( "Monthly Revenue Detail Report" )
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'MONTHLYREVENUESUMMARYREPORT')){
                    vm.tabNames.push( "Monthly Revenue Summary Report" )
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'ACCOUNTDETAILREPORT')){
                    vm.tabNames.push(  "Account Detail Report" )
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'SUPPRESSEDCODEREPORT')){
                    vm.tabNames.push(  "Suppressed Code Report" )
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'AUDITRECORDSREPORT')){
                    vm.tabNames.push(  "Audit Records Report" )
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'CONTRACTDETAILREPORT')){
                    vm.tabNames.push(  "Contract Detail Report" )
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'BILLINGSERVICELISTREPORT')){
                    vm.tabNames.push(  "Billing Service List Report" )
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'TICKETAUDITLOGREPORT')){
                    vm.tabNames.push( "Ticket Audit Log Report" )
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'PROCESSEDUNPROCESSEDREPORT')){
                    vm.tabNames.push( "Processed/Unprocessed Report" )
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'REVENUEBYCUSTOMERDISTRICTDATEREPORTNONGROUPED')){
                    vm.tabNames.push( "Revenue By Customer and District Date Report" )
                }
                if(Isrevenue){
                    if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'REVENUECOMPARISONREPORT')){
                    vm.tabNames.push( "Invoice Summary Report" )
                    }
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'MISSINGSETUPREPORT')){
                    vm.tabNames.push( "Missing Setup Report" )
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'BILLINGRULESMISSINGLIMITSREPORT')){
                    vm.tabNames.push( "Billing Rule Missing Limits Report" )
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'MISSINGRATESREPORT')){
                    vm.tabNames.push( "Missing Rates In Activities Report" )
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'MISSINGRATESINWORKCODEREPORT')){
                    vm.tabNames.push( "Missing Rates In WorkCode Report" )
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'INVOICESUMMARYBYWORKCODECOSTCENTERREPORT')){
                    vm.tabNames.push( "Invoice Summary By Work Code And Cost Center Report" )
                }
                if(vm.UserLicenseModules.filter(x => x.controllerName.toUpperCase() === 'INVOICEREPORT' && x.actionName.toUpperCase() === 'INVOICESUMMARYBYWORKCODECOSTCENTERREPORT')){
                    vm.tabNames.push( "Invoice Summary By Work Code And Cost Center Report" )
                }
                if(vm.NotesVal == "yes"){
                vm.tabNames.push( "Notes Report" )
            }
                vm.tabNames.push( "Billing Service Report" )
                vm.tabNames.push( "Billing Rule Report" )
            }

    },
    GetUserLicenseModulesReport: async function () {
            debugger;
            var vm = this;
            vm.isLoading=true;
            await  DataServices.GetUserLicenseModulesReport().then(response => {
                vm.isLoading=false;
                vm.UserLicenseModules = response.data.list;
            });
        },
        IsUsic: async function () {
                debugger;
                var vm = this;
                var url = `featureCode=USICBILLING`
                var parm = `featureCode=CBILLR`
                var parms = `featureCode="RevenueComparisonReport`
                await DataServices.CheckExtraFeatures(url).then((response) => {
                    if (response.data != null) {
                        this.IsUsicval = response.data;
                    }
                });
                await DataServices.CheckExtraFeatures(parm).then((response) => {
                    if (response.data != null) {
                        this.IsCheck = response.data;
                    }
                });
                await DataServices.CheckExtraFeatures(parms).then((response) => {
                    if (response.data != null) {
                        this.Isrevenue = response.data;
                    }
                });
            },
            GetNotes: async function () {
                debugger;
                var vm = this;
                var url = `configkey=EnableNotes`
                await DataServices.GetNotesByCompanyId(url).then((response) => {
                    debugger;
                    if (response.data != null) {
                        this.NotesVal = response.data;
                    }
                });
               
            },
        getTabIcon(name) {
                switch (name) {
                    case "Account Detail Report" :
                        return "fa fa-columns";
                    case "Audit Records Report" :
                        return "fa fa-list";
                    case "Billed/Unbilled Report" :
                        return "fa fa-money";
                    case "Billed/Unbilled Summary Report" :
                        return "fa fa-list-ul";
                    case "Billing Rule Report":
                        return "fa fa-align-justify"; 
                    case "Billing Rule Missing Limits Report":
                        return "fa fa-bar-chart"; 
                    case "Billing Service List Report" :
                        return "fa fa-align-justify";  
                    case "Billing Service Report" :
                        return "fa fa-align-justify";   
                    case "Contract Detail Report" :
                             return "fa fa-file-text";  
                    case "Flag Detail Report" :
                             return "fa fa-flag-o";
                    case "Flag Summary Report" :
                                 return "fa fa-flag";
                    case "Invoice Detail report":
                             return "fa fa-list-alt";
                    case "Invoice Summary By Work Code And Cost Center Report":
                             return "fa fa-file";
                    case "Invoice Summary Report":
                             return "fa fa-print";
                    case "Milestone Report":
                             return "fa fa-map-signs";
                    case "Missing Rates In WorkCode Report":
                            return "fa fa-money";
                    case "Missing Rates In Activities Report":
                            return "fa fa-ban";    
                    case "Missing Setup Report":
                            return "fa fa-cog";  
                    case "Monthly Revenue Detail Report":
                            return "fa fa-calendar-o";    
                    case "MTD Report":
                        return "fa fa-calculator";
                    case "Monthly Revenue Summary Report":
                        return "fa fa-calendar";
                    case "Notes Report":
                        return "fa fa-align-justify";
                    case "Processed/Unproccesed Report":
                        return "fa fa-file-o";
                    case "Revenue By Customer and District Date Report":
                        return "fa fa-user-circle";
                    case "Suppressed Code Report":
                        return "fa fa-file-code-o";
                    case "Ticket Audit Log Report":
                        return "fa fa-file-text"
                    default:
                        return "";
                }
            },
            activateTab(index) {
                this.activeKey = index;
            },
        },
    };
    </script>
    
<style scoped>
.left-tab-container {
  max-height: 70vh; 
  overflow-y: auto;
}
.left-tab .nav-link.left-menu a {
    width: 100%;
    display: flex;
}
.left-tab .nav-link.left-menu:hover, .listing:hover {
    color: #fff;
}
.left-tab .nav-link.left-menu.active .listing {
    color: #fff;
}
</style>
  
  