<template lang="en">
<div>
    <loader :is-visible="isLoading"></loader>
    <section class="main-content">
        <div ref="hellp" id="divMaindealData">
            <div class="border p-3">
                <Form ref="JobPostForm">
                    <dynamic-form lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
                    <div class="row placeholder">
                        <div class="col-md-12 p-0">
                            <ReportViewer v-if="parameter.length > 0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import DataServices from "../../services/DataService";
import ReportViewer from '../../views/HrReport/ReportViewer.vue';
export default {
    components: {
        ReportViewer
    },
    data() {
        return {
            isLoading: false,
            reportPath: null,
            parameter: [],
            DataLoaded: 0,
            FormSchema: [{
                    layoutType: "triple",
                    Data: [{
                            astype: "SelectField",
                            label: this.$t("Client Name"),
                            name: "Clientname",
                            value: "",
                            placeholder: this.$t('Select') + " " + this.$t('Client'),
                            mode: "tag",
                            config: {
                                options: [],
                                onChange: this.GetUtilityByClient
                            }
                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t("Utility Name"),
                            name: "UtilityName",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: [],
                            }
                        },
                        {
                            astype: "MultiSelectField",
                            label: this.$t("Modified By"),
                            name: "ModifiedBy",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: [],
                            }
                        }
                    ]
                },
                {
                    layoutType: "four",
                    Data: [{
                            astype: "DateField",
                            label: this.$t('Resolved Date (M/D/YYYY)'),
                            name: "ResolvedFromdate",
                            value: "",
                            placeholder: this.DateFormat,
                            config: {

                            }
                        },
                        {
                            astype: "DateField",
                            name: "ResolvedToDate",
                            value: "",
                            placeholder: this.$t('M/D/YYYY'),
                            config: {

                            }
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Flag Date (M/D/YYYY)'),
                            name: "FlagFromdate",
                            value: "",
                            placeholder: this.DateFormat,
                            config: {

                            }
                        },
                        {
                            astype: "DateField",
                            name: "FlagToDate",
                            value: "",
                            placeholder: this.$t('M/D/YYYY'),
                            config: {

                            }
                        }
                    ]
                },
                {
                    layoutType: "four",
                    Data: [{
                            astype: "textField",
                            label: this.$t("Ticket Number"),
                            name: "TicketNumber",
                            value: "",
                            placeholder: "Ticket Number"
                        },
                        {
                            astype: "DateField",
                            label: this.$t('Work Date (M/D/YYYY)'),
                            name: "WorkDateFromdate",
                            value: "",
                            placeholder: this.DateFormat,
                            config: {

                            }
                        },
                        {
                            astype: "DateField",
                            name: "WorkDateToDate",
                            value: "",
                            placeholder: this.$t('M/D/YYYY'),
                            config: {

                            }
                        },
                        {
                            astype: "SelectField",
                            label: this.$t("Cost Centers"),
                            name: "CostCenters",
                            value: "",
                            placeholder: this.$t('Select'),
                            mode: "tag",
                            config: {
                                options: [],
                            }
                        }
                    ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-search pr-2'></i>Search",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Clear all",
                    onClick: this.ClearAll
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.DataLoaded = 1;
        await vm.GetClient();
        await vm.GetUsers();
        await vm.GetCostCenters();
    },
    methods: {
        ClearAll: function () {
            var vm = this;
            (vm.FormSchema)[0].Data[0].value = '';
            (vm.FormSchema)[0].Data[1].value = '';
            (vm.FormSchema)[0].Data[2].value = '';
            (vm.FormSchema)[1].Data[0].value = '';
            (vm.FormSchema)[1].Data[1].value = '';
            (vm.FormSchema)[1].Data[2].value = '';
            (vm.FormSchema)[1].Data[3].value = '';
            (vm.FormSchema)[2].Data[0].value = '';
            (vm.FormSchema)[2].Data[1].value = '';
            (vm.FormSchema)[2].Data[2].value = '';
            (vm.FormSchema)[2].Data[3].value = '';
        },
        GetClient: async function () {
            var vm = this;
            var params = 'pageNumber=&pageSize=&Reqfrom=null&search=null&userId=null';
            await DataServices.GetClient(params).then((response) => {
                if (response.data.length > 0) {
                    var ClientData = response.data;
                    ClientData.forEach(element => {
                        var Obj = {
                            name: element.CHILD_NAME,
                            value: element.CHILD_USER_ID
                        }
                        vm.FormSchema[0].Data[0].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetUtilityByClient: async function (x, y, z) {
            var vm = this;
            var ClientIds = y.value;
            var url = `clientId=${ClientIds}&configid=0&Reqfrom=&clientIds=`;
            await DataServices.GetUtilityByClient(url).then((response) => {
                if (response.data.length > 0) {
                    var UtilityData = response.data;
                    UtilityData.forEach(element => {
                        var Obj = {
                            name: element.UTILITY_NAME,
                            value: element.UTILITY_ID
                        }
                        vm.FormSchema[0].Data[1].config.options.push(Obj);
                    });
                    vm.$refs.BarcodeReport.UpdateKeyValue();
                }
            });
        },
        GetUsers: async function () {
            var vm = this;
            var params = `isType=false&moduleName=InvoiceReport`;
            await DataServices.GetUsers(params).then((response) => {
                if (response.data != '') {
                    var UsersData = response.data;
                    UsersData.forEach(item => {
                        vm.FormSchema[0].Data[2].config.options.push({
                            name: item.UserName,
                            value: item.UserId
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },
        GetCostCenters: async function () {
            var vm = this;
            await DataServices.GetCostCenters().then((response) => {
                if (response.data != '') {
                    var CostCentresData = response.data;
                    CostCentresData.forEach(item => {
                        vm.FormSchema[2].Data[3].config.options.push({
                            name: item.TEXT,
                            value: item.VALUE
                        })
                    })
                }
                vm.$refs.BarcodeReport.UpdateKeyValue();
            });
        },
        onSubmit(e) {
            debugger;
            var reportviewerObj = $("#viewer").data("boldReportViewer");
            if (reportviewerObj != null) {
                reportviewerObj.destroy();
            }
            var vm = this;
            vm.isLoading = true;
            vm.reportPath = '';
            vm.parameter = [];
            let myObj = {
                reportName: "flagdetailreport",
                ClientIds: e.Clientname,
                UtilityIds: e.UtilityName.length > 0 ? e.UtilityName.map(item => item.value).join(",") : '',
                userIds: e.ModifiedBy.length > 0 ? e.ModifiedBy.map(item => item.value).join(",") : '',
                resolvedFromDate: e.ResolvedFromDate,
                resolvedToDate: e.ResolvedToDate,
                createdFromDate: e.FlagFromDate ,
                createdToDate: e.FlagToDate ,
                TicketNumber: e.TicketNumber,
                WorkDateFrom: e.WorkDateFromdate,
                WorkDateTo: e.WorkDateToDate,
                CostCenterId: e.CostCenters.length > 0 ? e.CostCenters.map(item => item.value).join(",") : ''
            }
            var postString = JSON.stringify(myObj);
            DataServices.ReportMain(postString).then(function (response) {
                vm.reportPath = response.data.reportpath;
                vm.parameter = response.data.parameters;
            })
            vm.isLoading = false;
        }
    }
};
</script>
